const n = normalizeWebhookBody(raw);
const prompt = [
  'You are an AAE specialist worker. Complete the task using ONLY execute_tool.',
  `Hard allowlist allowedTools=${JSON.stringify(n.allowedTools)}. Never call tools outside this list.`,
  'When finished, reply with JSON only: {"content":"result summary for your manager"}',
  `TaskContext: ${JSON.stringify(n.taskContext)}`,
  `History: ${JSON.stringify(n.chatHistory)}`,
].join('\n');
